import requests
from typing import Optional, Dict, Any

def fetch_api_data(timeout: int = 10) -> Optional[Dict[str, Any]]:
    """
    Fetches JSON data from the hypothetical API endpoint.
    Returns the parsed JSON data as a dictionary if successful, or None on failure.
    """
    url = "https://api.example.com/data"
    try:
        response = requests.get(url, timeout=timeout)
        response.raise_for_status()
        return response.json()
    except requests.exceptions.ConnectionError:
        print("Connection error: Unable to reach the server.")
    except requests.exceptions.Timeout:
        print("Request timed out.")
    except requests.exceptions.HTTPError as e:
        print(f"HTTP error occurred: {e}")
    except requests.exceptions.RequestException as e:
        print(f"An error occurred during the request: {e}")
    except ValueError as e:
        print(f"Error parsing JSON response: {e}")
    return None
